# ══ SECTION 2 — INPUT ════════════════════════════════════════════════════
st.markdown('<div id="sec-in" class="sec-wrap">', unsafe_allow_html=True)
st.markdown('<div class="sec-title"><div class="sec-icon" style="background:linear-gradient(135deg,#1d4ed8,#0891b2)">Rx</div>Patient Input <span class="badge">Step 1</span></div>', unsafe_allow_html=True)

with st.form("main_form"):
    st.markdown('<div class="gc"><div class="gc-lbl">Recipient Information</div>', unsafe_allow_html=True)
    c1,c2,c3=st.columns(3)
    with c1:
        Rg  = st.selectbox("Gender",            ["Male","Female"])
        Ra  = st.number_input("Age (years)",    0.0,20.0,8.0,0.1)
        Rb  = st.number_input("Body Mass (kg)", 0.0,120.0,25.0,0.5)
    with c2:
        Rd  = st.selectbox("Disease",           ["ALL","AML","chronic","nonmalignant","lymphoma"])
        Rdg = st.selectbox("Disease Group",     ["Malignant","Nonmalignant"])
        Rrg = st.selectbox("Risk Group",        ["Low","High"])
    with c3:
        Rabo= st.selectbox("Blood Type (ABO)",  ["O","A","B","AB"])
        Rrh = st.selectbox("Rh Factor",         ["Positive","Negative"])
        Rcmv= st.selectbox("Recipient CMV",     ["Negative","Positive"])
    st.markdown('</div>', unsafe_allow_html=True)

    st.markdown('<div class="gc"><div class="gc-lbl">Donor Information</div>', unsafe_allow_html=True)
    d1,d2,d3=st.columns(3)
    with d1:
        Da   = st.number_input("Donor Age",      0.0,80.0,35.0,0.1)
        Dabo = st.selectbox("Donor Blood Type",  ["O","A","B","AB"])
        Dcmv = st.selectbox("Donor CMV",         ["Negative","Positive"])
    with d2:
        Dsc  = st.selectbox("Stem Cell Source",  ["Bone Marrow","Peripheral Blood"])
        Dgm  = st.selectbox("Gender Match?",     ["No","Yes"])
        Dab  = st.selectbox("ABO Compatibility", ["Incompatible","Compatible"])
    with d3:
        Dcmvs= st.selectbox("CMV Combination",   ["-/- (both neg)","+/- (D+,R-)","-/+ (D-,R+)","+/+ (both pos)"])
        Dtr  = st.selectbox("Post-Relapse TX?",  ["No","Yes"])
        Drel = st.selectbox("Relapse?",          ["No","Yes"])
    st.markdown('</div>', unsafe_allow_html=True)

    with st.expander("HLA Matching & Disease Details — expand to fill"):
        h1,h2,h3=st.columns(3)
        with h1:
            Hm  = st.selectbox("HLA Match",          ["Mismatch","Full Match"])
            Hmi = st.selectbox("HLA Mismatch?",      ["No","Yes"])
            Han = st.selectbox("Antigen mismatches", ["Not applicable","0","1","2","3"])
        with h2:
            Hal = st.selectbox("Allele mismatches",  ["Not applicable","0","1","2","3"])
            Hgr = st.selectbox("HLA Group I?",       ["No","Yes"])
            Hii = st.selectbox("GvHD Grade II-IV?",  ["No","Yes"])
        with h3:
            Ra10= st.selectbox("Age > 10?",          ["No","Yes"])
            Rag = st.selectbox("Age Group",          ["0-5 yrs","5-10 yrs",">10 yrs"])

    with st.expander("Clinical & Lab Parameters — expand to fill"):
        l1,l2,l3=st.columns(3)
        with l1:
            Ccd34= st.number_input("CD34+ (x10^6/kg)",   0.0,200.0,7.0,0.1)
            Ccd3r= st.number_input("CD3/CD34 ratio",     0.0,500.0,5.0,0.1)
            Ccd3 = st.number_input("CD3+ (x10^8/kg)",   0.0,100.0,3.0,0.01)
        with l2:
            Canc = st.number_input("ANC Recovery (days)",0.0,100.0,15.0,0.5)
            Cplt = st.number_input("Platelet Recovery",  0.0,200.0,25.0,0.5)
            Cagv = st.selectbox("Acute GvHD III-IV?",   ["No","Yes"])
        with l3:
            Ccgv = st.selectbox("Extensive cGvHD?",     ["No","Yes"])
            Ctag = st.number_input("Time to aGvHD (days; 1e6=never)",0.0,1_000_000.0,1_000_000.0,1.0)

    st.markdown("<br>", unsafe_allow_html=True)
    submitted = st.form_submit_button("Compute Prediction", use_container_width=True)

st.markdown('</div><hr class="hr">', unsafe_allow_html=True)

# ── Run prediction ────────────────────────────────────────────────────────
if submitted:
    raw={
        "Recipientgender":      1 if Rg=="Male" else 0,
        "Stemcellsource":       1 if Dsc=="Peripheral Blood" else 0,
        "Donorage":Da,"Donorage35":1 if Da>35 else 0,
        "IIIV":YN[Hii],"Gendermatch":YN[Dgm],
        "DonorABO":ABO_M[Dabo],"RecipientABO":ABO_M[Rabo],
        "RecipientRh":1 if Rrh=="Positive" else 0,
        "ABOmatch":1 if Dab=="Compatible" else 0,
        "CMVstatus":CMV[Dcmvs],"DonorCMV":1 if Dcmv=="Positive" else 0,
        "RecipientCMV":1 if Rcmv=="Positive" else 0,
        "Disease":DIS[Rd],"Riskgroup":1 if Rrg=="High" else 0,
        "Txpostrelapse":YN[Dtr],"Diseasegroup":1 if Rdg=="Malignant" else 0,
        "HLAmatch":1 if Hm=="Full Match" else 0,"HLAmismatch":YN[Hmi],
        "Antigen":ANT[Han],"Alel":ANT[Hal],"HLAgrI":YN[Hgr],
        "Recipientage":Ra,"Recipientage10":YN[Ra10],
        "Recipientageint":AGI[Rag],"Relapse":YN[Drel],
        "aGvHDIIIIV":YN[Cagv],"extcGvHD":YN[Ccgv],
        "CD34kgx10d6":Ccd34,"CD3dCD34":Ccd3r,"CD3dkgx10d8":Ccd3,
        "Rbodymass":Rb,"ANCrecovery":Canc,"PLTrecovery":Cplt,
        "time_to_aGvHD_III_IV":Ctag,
    }
    if model and hasattr(model,"feature_names_in_"):
        exp=list(model.feature_names_in_)
        if "survival_time" in exp:
            raw["survival_time"]=0.0
        pdf=pd.DataFrame([raw])[exp]
    else:
        pdf=pd.DataFrame([raw])[FEATURE_COLS]

    if model:
        try:
            proba=float(model.predict_proba(pdf)[0][1])
            pred=int(model.predict(pdf)[0])
        except Exception as e:
            st.error(str(e)); proba,pred=0.5,0
    else:
        proba,pred=0.73,1

    st.session_state.update({
        "proba":proba,"pred":pred,"pdf":pdf,"show":True,
        "ps":{"Recipient":Rg,"Age":f"{Ra}y","Body Mass":f"{Rb}kg",
              "Disease":Rd,"Risk":Rrg,"R-ABO":Rabo,"R-CMV":Rcmv,
              "Donor Age":f"{Da}y","D-ABO":Dabo,"SC Source":Dsc,
              "ABO":Dab,"HLA":Hm,"Relapse":Drel,
              "CD34+":f"{Ccd34}","ANC":f"{Canc}d"},
    })

show=st.session_state.get("show",False)
proba=st.session_state.get("proba",None)
pred=st.session_state.get("pred",None)
pdf=st.session_state.get("pdf",None)

# ══ SECTION 3 — PREDICTION ═══════════════════════════════════════════════
st.markdown('<div id="sec-res" class="sec-wrap">', unsafe_allow_html=True)
st.markdown('<div class="sec-title"><div class="sec-icon" style="background:linear-gradient(135deg,#065f46,#0891b2)">Px</div>Prediction Result <span class="badge">Step 2</span></div>', unsafe_allow_html=True)

if not show:
    st.markdown('<div class="nb">Fill in Patient Input above and click Compute Prediction — results appear here automatically.</div>', unsafe_allow_html=True)
else:
    L,R=st.columns([1,1.45])
    clr="#34d399" if pred==1 else "#f87171"
    with L:
        if pred==1:
            st.markdown(f'<div class="rok"><div class="ric">&#10003;</div><div class="rv">Transplant Likely Successful</div><div class="rp">{proba:.1%}</div><div class="rs">Estimated survival probability</div></div>',unsafe_allow_html=True)
        else:
            st.markdown(f'<div class="rfail"><div class="ric">&#9888;</div><div class="rv">High Risk of Failure</div><div class="rp">{1-proba:.1%}</div><div class="rs">Estimated failure probability</div></div>',unsafe_allow_html=True)
        st.markdown("<br>",unsafe_allow_html=True)
        # Gauge bar
        fig,ax=dark_fig(5.2,0.7)
        ax.barh(0,proba,color=clr,height=0.32,alpha=0.9,zorder=2)
        ax.barh(0,1-proba,left=proba,color="#0d1f4a",height=0.32,zorder=2)
        ax.axvline(0.5,color="#38bdf8",lw=1,ls="--",zorder=3)
        ax.set_xlim(0,1);ax.set_ylim(-0.4,0.4)
        ax.set_xticks([0,.25,.5,.75,1])
        ax.set_xticklabels(["0%","25%","50%","75%","100%"],fontsize=7.5,color=MUTED)
        ax.set_yticks([])
        for sp in ax.spines.values(): sp.set_visible(False)
        ax.text(min(proba+0.02,0.9),0,f"{proba:.1%}",
                va="center",fontsize=9.5,fontweight="bold",color=clr)
        plt.tight_layout(pad=0.1)
        st.pyplot(fig,use_container_width=True);plt.close()
    with R:
        st.markdown('<div class="gc"><div class="gc-lbl">Patient Summary</div>',unsafe_allow_html=True)
        ps=st.session_state.get("ps",{})
        c1,c2=st.columns(2)
        for i,(k,v) in enumerate(ps.items()):
            (c1 if i%2==0 else c2).metric(k,v)
        st.markdown('</div>',unsafe_allow_html=True)

st.markdown('</div><hr class="hr">',unsafe_allow_html=True)

# ══ SECTION 4 — SHAP ═════════════════════════════════════════════════════
st.markdown('<div id="sec-shap" class="sec-wrap">',unsafe_allow_html=True)
st.markdown('<div class="sec-title"><div class="sec-icon" style="background:linear-gradient(135deg,#7c3aed,#0891b2)">Sx</div>SHAP Explanation <span class="badge">Step 3</span></div>',unsafe_allow_html=True)

if not show:
    st.markdown('<div class="nb">SHAP analysis will appear here after prediction.</div>',unsafe_allow_html=True)
elif model is None:
    st.markdown('<div class="nb">No model loaded — place xgboost.pkl in the models/ folder.</div>',unsafe_allow_html=True)
else:
    try:
        import shap
        with st.spinner("Computing SHAP values..."):
            ex=shap.TreeExplainer(model)
            svr=ex.shap_values(pdf)
            sv=svr[1] if isinstance(svr,list) else svr

        t1,t2=st.tabs(["Feature Impact — This Patient","Global Feature Importance"])
        with t1:
            ct=(pd.DataFrame({"Feature":pdf.columns,"Value":pdf.iloc[0].values,"SHAP":sv[0]})
                .sort_values("SHAP",key=abs,ascending=False).head(15).reset_index(drop=True))
            ct.index+=1
            fig,ax=dark_fig(9,4.5)
            colors=["#22d3ee" if v>0 else "#f87171" for v in ct["SHAP"]]
            ypos=range(len(ct))
            ax.barh(list(ypos),ct["SHAP"].tolist(),
                    color=colors,alpha=0.82,edgecolor="none",height=0.52)
            ax.set_yticks(list(ypos))
            ax.set_yticklabels(ct["Feature"].tolist(),fontsize=8,color=WHITE)
            ax.axvline(0,color="#38bdf8",lw=1,alpha=0.5)
            ax.set_xlabel("SHAP Value",color=MUTED,fontsize=9)
            for i,(bar_val) in enumerate(ct["SHAP"]):
                ax.text(bar_val+(0.0005 if bar_val>=0 else -0.0005),i,
                        f"{bar_val:+.3f}",va="center",
                        ha="left" if bar_val>=0 else "right",
                        fontsize=6.5,color=WHITE,fontweight="600")
            plt.tight_layout(pad=1.2)
            st.pyplot(fig,use_container_width=True);plt.close()
            st.markdown("<br>",unsafe_allow_html=True)
            st.markdown('<div class="gc"><div class="gc-lbl">Feature Contributions</div>',unsafe_allow_html=True)
            def cs(v): return "background:rgba(34,211,238,.1);color:#67e8f9" if v>0 else "background:rgba(248,113,113,.1);color:#fca5a5"
            st.dataframe(ct.style.applymap(cs,subset=["SHAP"]).format({"SHAP":"{:+.4f}","Value":"{:.3g}"}),use_container_width=True)
            st.markdown('</div>',unsafe_allow_html=True)
        with t2:
            imp=(pd.DataFrame({"Feature":pdf.columns,"Mean |SHAP|":np.abs(sv[0])})
                 .sort_values("Mean |SHAP|",ascending=True).tail(15))
            fig2,ax2=dark_fig(9,4.5)
            n=len(imp)
            bar_colors=plt.cm.Blues(np.linspace(0.35,0.9,n))
            ypos2=range(n)
            ax2.barh(list(ypos2),imp["Mean |SHAP|"].tolist(),
                     color=bar_colors,edgecolor="none",height=0.52)
            ax2.set_yticks(list(ypos2))
            ax2.set_yticklabels(imp["Feature"].tolist(),fontsize=8,color=WHITE)
            ax2.set_xlabel("Mean |SHAP|",color=MUTED,fontsize=9)
            plt.tight_layout(pad=1.2)
            st.pyplot(fig2,use_container_width=True);plt.close()
    except ImportError:
        st.markdown('<div class="nb">SHAP not installed — run: <code style="color:#38bdf8">pip install shap</code></div>',unsafe_allow_html=True)
    except Exception as e:
        st.error(f"SHAP error: {e}")

st.markdown('</div><hr class="hr">',unsafe_allow_html=True)

