st.markdown('<div id="sec-met" class="sec-wrap">',unsafe_allow_html=True)
st.markdown('<div class="sec-title"><div class="sec-icon" style="background:linear-gradient(135deg,#0f766e,#0891b2)">Mx</div>Model Metrics <span class="badge">Reference</span></div>',unsafe_allow_html=True)

df_m=pd.DataFrame({
    "Model":["XGBoost","LightGBM","Random Forest"],
    "ROC-AUC":[0.8721,0.8590,0.8435],
    "Accuracy":[0.8289,0.8158,0.7895],
    "Precision":[0.8462,0.8333,0.8000],
    "Recall":[0.8148,0.8148,0.7778],
    "F1-Score":[0.8302,0.8240,0.7887],
})
st.markdown('<div class="gc"><div class="gc-lbl">Performance Comparison</div>',unsafe_allow_html=True)
st.dataframe(df_m.set_index("Model").style.highlight_max(color="rgba(56,189,248,0.18)",axis=0).format("{:.4f}"),use_container_width=True)
st.markdown('</div>',unsafe_allow_html=True)

kc=st.columns(5)
for col,(v,l) in zip(kc,[("0.8721","ROC-AUC"),("82.9%","Accuracy"),("84.6%","Precision"),("81.5%","Recall"),("83.0%","F1-Score")]):
    with col:
        st.markdown(f'<div class="kpi"><div class="kpi-v">{v}</div><div class="kpi-l">{l}</div><div class="kpi-b">XGBoost</div></div>',unsafe_allow_html=True)

st.markdown("<br>",unsafe_allow_html=True)
ch,cw=st.columns([1.4,1])
with ch:
    st.markdown('<div class="gc"><div class="gc-lbl">ROC-AUC Comparison</div>',unsafe_allow_html=True)
    fig,ax=dark_fig(7,3.2)
    mdls=["XGBoost","LightGBM","Random Forest"]
    sc_vals=[0.8721,0.8590,0.8435]
    bar_clrs=["#38bdf8","#0ea5e9","#0369a1"]
    bars=ax.barh(mdls,sc_vals,color=bar_clrs,alpha=0.88,height=0.42,edgecolor="none")
    ax.set_xlim(0.77,0.91)
    for bar,s in zip(bars,sc_vals):
        ax.text(s+0.001,bar.get_y()+bar.get_height()/2,
                f"{s:.4f}",va="center",fontsize=9,fontweight="700",color=WHITE)
    ax.set_xlabel("ROC-AUC"); ax.tick_params(left=False)
    ax.set_yticklabels(mdls,fontsize=9,color=WHITE)
    plt.tight_layout(pad=1.0)
    st.pyplot(fig,use_container_width=True);plt.close()
    st.markdown('</div>',unsafe_allow_html=True)

with cw:
    st.markdown('<div class="gc"><div class="gc-lbl">Why XGBoost?</div>',unsafe_allow_html=True)
    st.markdown('<p style="color:#c7e4f9;font-size:.83rem;line-height:1.8;margin:0"><b style="color:#38bdf8">ROC-AUC</b> measures discrimination between survivors and non-survivors regardless of threshold — the key metric in medical classification.<br><br><b style="color:#38bdf8">Recall</b> is critical: a missed failure (false negative) carries far greater consequences than a false alarm.<br><br>XGBoost achieved the best <b style="color:#38bdf8">ROC-AUC 0.8721</b> and Recall 81.5%.</p>',unsafe_allow_html=True)
    st.markdown('</div>',unsafe_allow_html=True)

st.markdown('<div class="gc"><div class="gc-lbl">Class Distribution &amp; SMOTE Strategy</div>',unsafe_allow_html=True)
bi1,bi2=st.columns([1.8,1])
with bi1:
    st.markdown('<p style="color:#c7e4f9;font-size:.83rem;line-height:1.85;margin:0"><b style="color:#38bdf8">Original distribution:</b> 60% survived &nbsp;·&nbsp; 40% not survived<br><b style="color:#38bdf8">SMOTE</b> was applied only on training data, strictly after train/test split — ensuring zero data leakage. Synthetic minority-class samples balance training without distorting test performance.</p>',unsafe_allow_html=True)
with bi2:
    fig3,ax3=plt.subplots(figsize=(3.3,3.2))
    fig3.patch.set_facecolor("#04112a")
    ax3.set_facecolor("#04112a")
    ax3.pie([60,40],
            labels=["Survived\n60%","Not Survived\n40%"],
            colors=["#0ea5e9","#1e3a6e"],
            autopct="%1.0f%%",startangle=90,
            textprops={"fontsize":8,"color":"#e0f2fe","fontweight":"600"},
            wedgeprops={"edgecolor":"#04112a","linewidth":2})
    plt.tight_layout()
    st.pyplot(fig3,use_container_width=False);plt.close()
st.markdown('</div>',unsafe_allow_html=True)
st.markdown('</div>',unsafe_allow_html=True)

